args.sparql:
SELECT ?player ?playerLabel WHERE {
  ?player wdt:P5200 ?homeRuns.
  ?player rdfs:label ?playerLabel.
  FILTER (lang(?playerLabel) = "en").
  FILTER (isNumeric(?homeRuns)).
} ORDER BY DESC(?homeRuns) LIMIT 1

SELECT ?player ?playerLabel WHERE {
  ?player wdt:P5508 ?homeRuns.
  ?player rdfs:label ?playerLabel.
  FILTER (lang(?playerLabel) = "en").
  FILTER (isNumeric(?homeRuns)).
} ORDER BY DESC(?homeRuns) LIMIT 1

SELECT ?player ?playerLabel ?homeRuns WHERE {
  ?player wdt:P31 wd:Q5122937;
          wdt:P7074 ?value.
  ?value wikibase:quantityValue ?quantity.
  ?player rdfs:label ?playerLabel.
  FILTER (lang(?playerLabel) = 'en').
  BIND(xsd:integer(?quantity) AS ?homeRuns)
} ORDER BY DESC(?homeRuns) LIMIT 1
